hstar_hempty_l.solution:
Lemma hstar_hempty_l : forall H,
  \[] \* H = H.
Proof using.
  intros. apply hprop_eq. intros h. split.
  { intros (h1&h2&M1&M2&D&U). hnf in M1. subst.
    rewrite Fmap.union_empty_l. auto. }
  { intros M. exists Fmap.empty h. splits.
    { hnf. auto. }
    { auto. }
    { auto. }
    { rewrite Fmap.union_empty_l. auto. } }
Qed.

hstar_assoc.solution:
Lemma hstar_assoc : forall H1 H2 H3,
  (H1 \* H2) \* H3 = H1 \* (H2 \* H3).
Proof using.
  intros. apply hprop_eq. split.
  { intros (h'&h3&M1&M2&D&U). destruct M1 as (h1&h2&M3&M4&D'&U').
    subst h'. rewrite Fmap.disjoint_union_eq_l in D.
    exists h1 (h2 \u h3). splits.
    { apply M3. }
    { exists* h2 h3. }
    { rewrite* @Fmap.disjoint_union_eq_r. }
    { rewrite* @Fmap.union_assoc in U. } }
  { intros (h1&h'&M1&M2&D&U). destruct M2 as (h2&h3&M3&M4&D'&U').
    subst h'. rewrite Fmap.disjoint_union_eq_r in D.
    exists (h1 \u h2) h3. splits.
    { exists* h1 h2. }
    { apply M4. }
    { rewrite* @Fmap.disjoint_union_eq_l. }
    { rewrite* @Fmap.union_assoc. } }
Qed.

