Lemma hstar_hpure_l : forall P H h,
  (\[P] \* H) h = (P /\ H h).
Proof using.
  intros. apply propositional_extensionality. split.
  { intros (h1&h2&(E1&HP)&M2&D&U). subst. rewrite Fmap.union_empty_l in U.
    subst. split. { auto. } { auto. } }
  { intros (HP&MH). exists Fmap.empty h. splits.
    { hnf. auto. }
    { auto. }
    { auto. }
    { rewrite Fmap.union_empty_l. auto. } }
Qed.
